import boto3
import json
import logging
from typing import Dict, Any, Callable
from concurrent.futures import ThreadPoolExecutor
import time

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

class SQSWorker:
    def __init__(self, queue_url: str, max_workers: int = 10):
        self.sqs = boto3.client('sqs')
        self.queue_url = queue_url
        self.max_workers = max_workers
        self.message_handlers: Dict[str, Callable] = {}
        self.executor = ThreadPoolExecutor(max_workers=max_workers)
        
    def register_handler(self, message_type: str, handler: Callable):
        """Register a handler function for a specific message type"""
        self.message_handlers[message_type] = handler
        
    def process_message(self, message: Dict[str, Any]):
        """Process a single SQS message"""
        try:
            message_body = message.get('Body')
            if not message_body:
                logger.warning("Empty message body")
                return False
                
            # Parse message body
            if isinstance(message_body, str):
                try:
                    message_data = json.loads(message_body)
                except json.JSONDecodeError:
                    logger.error("Failed to parse JSON message")
                    return False
            else:
                message_data = message_body
                
            # Extract message type
            message_type = message_data.get('type')
            if not message_type:
                logger.warning("Message type not found")
                return False
                
            # Get handler for message type
            handler = self.message_handlers.get(message_type)
            if not handler:
                logger.warning(f"No handler registered for message type: {message_type}")
                return False
                
            # Execute handler
            logger.info(f"Processing message type: {message_type}")
            handler(message_data)
            
            return True
            
        except Exception as e:
            logger.error(f"Error processing message: {str(e)}")
            return False
            
    def poll_messages(self, batch_size: int = 10, wait_time: int = 20):
        """Poll messages from SQS queue"""
        while True:
            try:
                response = self.sqs.receive_message(
                    QueueUrl=self.queue_url,
                    MaxNumberOfMessages=batch_size,
                    WaitTimeSeconds=wait_time,
                    MessageAttributeNames=['All'],
                    AttributeNames=['All']
                )
                
                messages = response.get('Messages', [])
                
                if not messages:
                    logger.info("No messages in queue")
                    time.sleep(1)
                    continue
                    
                logger.info(f"Received {len(messages)} messages")
                
                # Process messages in parallel
                futures = []
                for message in messages:
                    future = self.executor.submit(self.process_message, message)
                    futures.append(future)
                    
                # Wait for all futures to complete
                for future in futures:
                    try:
                        future.result(timeout=30)
                    except Exception as e:
                        logger.error(f"Error in message processing: {str(e)}")
                        
                # Delete processed messages
                entries = [
                    {'Id': str(i), 'ReceiptHandle': message['ReceiptHandle']}
                    for i, message in enumerate(messages)
                ]
                
                if entries:
                    self.sqs.delete_message_batch(QueueUrl=self.queue_url, Entries=entries)
                    logger.info(f"Deleted {len(entries)} messages from queue")
                    
            except Exception as e:
                logger.error(f"Error polling messages: {str(e)}")
                time.sleep(5)
                
    def start(self):
        """Start the worker"""
        logger.info("Starting SQS worker")
        self.poll_messages()
        
    def stop(self):
        """Stop the worker"""
        logger.info("Stopping SQS worker")
        self.executor.shutdown(wait=True)

